// ==================== 配置区（在此修改）====================
const CONFIG = {
  BACKEND_BASE_URL: 'http://localhost:5000',
  JWT_TOKEN: 'your-jwt-token-here',  // ⚠️ 必须修改：从浏览器 F12 → Application → Local Storage → xu_news_token 复制
  RSS_SOURCES: [
    'https://example.com/rss',
    'https://news.example.org/feed'
  ],
  SOURCE_NAME: '示例新闻网',
  SMTP_USER: 'your-email@qq.com',    // ⚠️ 必须修改：你的 QQ 邮箱
  SMTP_PASS: 'your-qq-auth-code',    // ⚠️ 必须修改：QQ 邮箱授权码（16位）
  SMTP_TO: 'recipient@example.com'   // ⚠️ 必须修改：接收邮件的邮箱
};

// ==================== 保存到输出 ====================
return [{ json: CONFIG }];

// 解析 RSS/HTML，提取新闻条目
const config = $('Code-配置中心').first().json;
const xml = $input.first().body || $input.first().json.data || '';

if (!xml) {
  console.error('RSS 内容为空');
  return [];
}

// 简单的 RSS 解析（正则方式）
try {
  const titleReg = /<title>(?:<!\[CDATA\[)?(.+?)(?:\]\]>)?<\/title>/gs;
  const linkReg = /<link>(?:<!\[CDATA\[)?(.+?)(?:\]\]>)?<\/link>/gs;
  const pubDateReg = /<pubDate>(.+?)<\/pubDate>/gs;
  const descReg = /<description>(?:<!\[CDATA\[)?([\s\S]+?)(?:\]\]>)?<\/description>/gs;

  const titles = [...xml.matchAll(titleReg)];
  const links = [...xml.matchAll(linkReg)];
  const pubDates = [...xml.matchAll(pubDateReg)];
  const descs = [...xml.matchAll(descReg)];

  const items_parsed = [];
  const seenUrls = new Set();

  // 跳过第一个（频道信息）
  for (let i = 1; i < Math.min(titles.length, links.length); i++) {
    const title = (titles[i][1] || '').trim();
    const link = (links[i][1] || '').trim();
    const pubDate = pubDates[i] ? (pubDates[i][1] || '').trim() : '';
    const desc = descs[i] ? (descs[i][1] || '').trim() : '';

    if (title && link && !seenUrls.has(link)) {
      seenUrls.add(link);

      // 清理内容
      const cleanContent = desc.replace(/<[^>]*>/g, '').replace(/&[a-z]+;/gi, ' ').trim();

      items_parsed.push({
        json: {
          title: title,
          url: link,
          published_at: pubDate,
          content: cleanContent || title,  // 如果没有描述，使用标题
          source: config.SOURCE_NAME,
          type: 'text'
        }
      });
    }
  }

  console.log(`✓ 解析到 ${items_parsed.length} 条新闻`);
  return items_parsed;

} catch (error) {
  console.error('RSS 解析失败:', error);
  return [];
}

// 统计成功/失败数量
const allResults = $input.all();
const successCount = allResults.filter(item => item.json.code === 0).length;
const failedCount = allResults.length - successCount;

console.log(`入库统计: 成功 ${successCount}, 失败 ${failedCount}`);

return [{
  json: {
    total: allResults.length,
    success: successCount,
    failed: failedCount,
    timestamp: new Date().toISOString()
  }
}];

