// Markdown 转 HTML（简易版）
const config = $('Code-配置中心').first().json;
const stats = $('Code-汇总统计').first().json;
const llmResponse = $input.first().json;
const markdown = llmResponse.data?.answer || '暂无摘要';

// 简易 Markdown 转 HTML
let html = markdown
  .replace(/^### (.+)$/gm, '<h3>$1</h3>')
  .replace(/^## (.+)$/gm, '<h2>$1</h2>')
  .replace(/^# (.+)$/gm, '<h1>$1</h1>')
  .replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
  .replace(/\*(.+?)\*/g, '<em>$1</em>')
  .replace(/\[(.+?)\]\((.+?)\)/g, '<a href="$2" target="_blank">$1</a>')
  .replace(/^- (.+)$/gm, '<li>$1</li>')
  .replace(/^\* (.+)$/gm, '<li>$1</li>')
  .replace(/^\d+\. (.+)$/gm, '<li>$1</li>')
  .replace(/\n\n/g, '</p><p>')
  .replace(/\n/g, '<br>');

html = html.replace(/(<li>.*?<\/li>)/gs, '<ul>$1</ul>');
html = '<div>' + html + '</div>';

const now = new Date();
const dateStr = now.toLocaleDateString('zh-CN', { year: 'numeric', month: 'long', day: 'numeric' });
const timeStr = now.toLocaleTimeString('zh-CN');

// 完整 HTML 邮件
const fullHtml = `
<!DOCTYPE html>
<html lang="zh-CN">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>XU-News 日报</title>
  <style>
    body {
      font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei', sans-serif;
      line-height: 1.8;
      color: #333;
      max-width: 800px;
      margin: 0 auto;
      padding: 20px;
      background-color: #f5f5f5;
    }
    .container {
      background: white;
      border-radius: 8px;
      box-shadow: 0 2px 8px rgba(0,0,0,0.1);
      padding: 30px;
    }
    .header {
      text-align: center;
      padding-bottom: 20px;
      border-bottom: 3px solid #0ea5e9;
      margin-bottom: 30px;
    }
    .header h1 {
      color: #0ea5e9;
      margin: 0 0 10px 0;
      font-size: 28px;
    }
    .meta {
      color: #666;
      font-size: 14px;
    }
    .stats {
      display: flex;
      justify-content: space-around;
      background: #f0f9ff;
      padding: 20px;
      border-radius: 8px;
      margin-bottom: 30px;
    }
    .stat-item {
      text-align: center;
    }
    .stat-number {
      font-size: 32px;
      font-weight: bold;
      color: #0ea5e9;
    }
    .stat-label {
      font-size: 14px;
      color: #666;
      margin-top: 5px;
    }
    h2 { color: #0369a1; margin-top: 30px; }
    h3 { color: #075985; margin-top: 20px; }
    ul {
      background: #f9fafb;
      padding: 20px 20px 20px 40px;
      border-left: 4px solid #0ea5e9;
      border-radius: 4px;
      margin: 15px 0;
    }
    li {
      margin: 10px 0;
      line-height: 1.6;
    }
    a {
      color: #0ea5e9;
      text-decoration: none;
    }
    a:hover {
      text-decoration: underline;
    }
    .footer {
      margin-top: 40px;
      padding-top: 20px;
      border-top: 1px solid #e5e7eb;
      text-align: center;
      font-size: 12px;
      color: #9ca3af;
    }
    .btn {
      display: inline-block;
      padding: 12px 24px;
      background: #0ea5e9;
      color: white;
      text-decoration: none;
      border-radius: 6px;
      margin-top: 20px;
    }
    .btn:hover {
      background: #0284c7;
    }
  </style>
</head>
<body>
  <div class="container">
    <div class="header">
      <h1>🗞️ XU-News AI-RAG 日报</h1>
      <div class="meta">
        <p>📅 ${dateStr} ${timeStr}</p>
      </div>
    </div>

    <div class="stats">
      <div class="stat-item">
        <div class="stat-number">${stats.total}</div>
        <div class="stat-label">处理总数</div>
      </div>
      <div class="stat-item">
        <div class="stat-number">${stats.success}</div>
        <div class="stat-label">成功入库</div>
      </div>
      <div class="stat-item">
        <div class="stat-number">${stats.failed}</div>
        <div class="stat-label">失败/重复</div>
      </div>
    </div>

    <h2>📰 今日新闻摘要</h2>
    ${html}

    <div style="text-align: center;">
      <a href="http://localhost:5173" class="btn">访问系统查看详情</a>
    </div>

    <div class="footer">
      <p>本邮件由 XU-News AI-RAG 系统自动生成</p>
      <p>基于 RAG 技术 · 智能问答 · 新闻聚类</p>
    </div>
  </div>
</body>
</html>
`;

return [{
  json: {
    html_content: fullHtml,
    subject: `🗞️ XU-News 日报 - ${dateStr} - 新增 ${stats.success} 条`,
    to_email: config.SMTP_TO,
    from_email: config.SMTP_USER,
    smtp_host: 'smtp.qq.com',
    smtp_port: 465,
    smtp_user: config.SMTP_USER,
    smtp_pass: config.SMTP_PASS,
    stats: stats
  }
}];

// 错误处理
const config = $('Code-配置中心').first().json;
const error = $input.first();

const logData = {
  timestamp: new Date().toISOString(),
  workflow: 'News Ingest & Daily Notify',
  error_node: error.node || 'Unknown',
  error_message: error.error?.message || JSON.stringify(error),
  level: 'ERROR'
};

console.error('❌ 工作流执行失败:', logData);

return [{
  json: {
    ...logData,
    backend_url: config.BACKEND_BASE_URL + '/api/system/logs',
    jwt_token: config.JWT_TOKEN
  }
}];
